INSERT INTO public.questions (id, exam_id, paper_id, subject_id, chapter_id, question_type, question_text, options, correct_answer, correct_answer_json, auto_gradable, source, is_active, version, source_meta, explanation)
VALUES
  ('aboriginal-e3452428-moex-00381', 'aboriginal-e3452428', 'aboriginal-e3452428-moex-110-6ed013db', 'sub-aboriginal-e3452428-07', NULL, 'single_choice', '有關原住民族土地或部落範圍土地劃設小組之組成規定，下列敘述何者錯誤？', '["劃設小組係由部落自主組成", "劃設人員具有原住民身分者，不得少於總數二分之一", "劃設小組由鄉（鎮、市、區）公所協助部落組成", "原住民族委員會得委託機關團體協助辦理劃設作業"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:36:59+00:00", "source_pdf_sha1": "6069e65a1298", "answer_pdf_sha1": "c5158b77d9cd", "source_family": "moex-gov-tw", "moex": {"exam_code": "110150", "c": "401", "s": "0213", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "法學知識與英文(包括中華民國憲法、原住民族行政及法規、英文)", "year": "110", "exam_name": "110年公務人員特種考試外交領事人員及外交行政人員考試、民航人員考試、原住民族考試", "original_question_number": 21, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "一般民政"}'::jsonb, NULL),
  ('aboriginal-e3452428-moex-00382', 'aboriginal-e3452428', 'aboriginal-e3452428-moex-110-6ed013db', 'sub-aboriginal-e3452428-07', NULL, 'single_choice', '依現行法之規定，原住民族傳統領域土地之劃設成果，應提請何一組織討論與議決？', '["部落會議", "原住民保留地土地權利審查委員會", "直轄市、縣（市）議會", "鄉（鎮、市）民代表會"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:36:59+00:00", "source_pdf_sha1": "6069e65a1298", "answer_pdf_sha1": "c5158b77d9cd", "source_family": "moex-gov-tw", "moex": {"exam_code": "110150", "c": "401", "s": "0213", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "法學知識與英文(包括中華民國憲法、原住民族行政及法規、英文)", "year": "110", "exam_name": "110年公務人員特種考試外交領事人員及外交行政人員考試、民航人員考試、原住民族考試", "original_question_number": 22, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "一般民政"}'::jsonb, NULL),
  ('aboriginal-e3452428-moex-00383', 'aboriginal-e3452428', 'aboriginal-e3452428-moex-110-6ed013db', 'sub-aboriginal-e3452428-07', NULL, 'single_choice', '位於花蓮縣吉安鄉的全牛料理餐廳，經營者甲為阿美族馬太鞍部落族人，明知「馬蘭阿美飲酒歡樂歌」 （專用權人為大馬蘭地區部落）、「阿美族馬太鞍部落男性傳統服飾：五片流蘇裙」（專用權人為阿美族 馬太鞍部落）係具傳統智慧創作專用權之權利標的，為招攬生意，在其餐廳使用前述已取得智慧創作 專用權之權利內容，請問下列那項利用行為，構成智慧創作專用權之侵害？', '["甲穿著「五片流蘇裙」提供服務", "甲使用「五片流蘇裙」之圖案設計T恤販售", "甲於營業時間公開演唱「馬蘭阿美飲酒歡樂歌」", "甲於營業時間聘請大馬蘭地區部落族人演唱「馬蘭阿美飲酒歡樂歌」"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:36:59+00:00", "source_pdf_sha1": "6069e65a1298", "answer_pdf_sha1": "c5158b77d9cd", "source_family": "moex-gov-tw", "moex": {"exam_code": "110150", "c": "401", "s": "0213", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "法學知識與英文(包括中華民國憲法、原住民族行政及法規、英文)", "year": "110", "exam_name": "110年公務人員特種考試外交領事人員及外交行政人員考試、民航人員考試、原住民族考試", "original_question_number": 23, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "一般民政"}'::jsonb, NULL),
  ('aboriginal-e3452428-moex-00384', 'aboriginal-e3452428', 'aboriginal-e3452428-moex-110-6ed013db', 'sub-aboriginal-e3452428-07', NULL, 'single_choice', '依原住民族教育法之規定，教育部及原住民族委員會應鼓勵原住民學生達多少人數之公立大專校院， 設置原住民族學生資源中心？', '["20人", "30人", "50人", "100人"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:36:59+00:00", "source_pdf_sha1": "6069e65a1298", "answer_pdf_sha1": "c5158b77d9cd", "source_family": "moex-gov-tw", "moex": {"exam_code": "110150", "c": "401", "s": "0213", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "法學知識與英文(包括中華民國憲法、原住民族行政及法規、英文)", "year": "110", "exam_name": "110年公務人員特種考試外交領事人員及外交行政人員考試、民航人員考試、原住民族考試", "original_question_number": 24, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "一般民政"}'::jsonb, NULL),
  ('aboriginal-e3452428-moex-00385', 'aboriginal-e3452428', 'aboriginal-e3452428-moex-110-6ed013db', 'sub-aboriginal-e3452428-07', NULL, 'single_choice', '下列有關公有土地增劃編原住民保留地審查作業之辦理機關，何者錯誤？', '["原住民族委員會為主辦機關", "財政部國有財產署為協辦機關", "直轄市或縣政府為協辦機關", "鄉（鎮、市、區）公所為執行機關"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:36:59+00:00", "source_pdf_sha1": "6069e65a1298", "answer_pdf_sha1": "c5158b77d9cd", "source_family": "moex-gov-tw", "moex": {"exam_code": "110150", "c": "401", "s": "0213", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "法學知識與英文(包括中華民國憲法、原住民族行政及法規、英文)", "year": "110", "exam_name": "110年公務人員特種考試外交領事人員及外交行政人員考試、民航人員考試、原住民族考試", "original_question_number": 25, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "一般民政"}'::jsonb, NULL),
  ('aboriginal-e3452428-moex-00386', 'aboriginal-e3452428', 'aboriginal-e3452428-moex-110-6ed013db', 'sub-aboriginal-e3452428-07', NULL, 'single_choice', '有關原住民族綜合發展基金之敘述，下列何者錯誤？', '["原住民族綜合發展基金由政府設立，辦理原住民族經濟發展業務、輔導事業機構、住宅之興辦、租 售、建購及修繕業務", "基金之法定來源包括原住民族地區溫泉取用費提撥款", "基金之法定用途包括原住民族就學基金支出", "原住民族綜合發展基金管理會召集人，為原住民族委員會副主任委員"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:36:59+00:00", "source_pdf_sha1": "6069e65a1298", "answer_pdf_sha1": "c5158b77d9cd", "source_family": "moex-gov-tw", "moex": {"exam_code": "110150", "c": "401", "s": "0213", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "法學知識與英文(包括中華民國憲法、原住民族行政及法規、英文)", "year": "110", "exam_name": "110年公務人員特種考試外交領事人員及外交行政人員考試、民航人員考試、原住民族考試", "original_question_number": 26, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "一般民政"}'::jsonb, NULL),
  ('aboriginal-e3452428-moex-00387', 'aboriginal-e3452428', 'aboriginal-e3452428-moex-110-6ed013db', 'sub-aboriginal-e3452428-07', NULL, 'single_choice', '依據原住民族傳統智慧創作保護條例，經認定為智慧創作者，依法取得智慧創作專用權之敘述，何者 錯誤？', '["智慧創作經認定屬於申請人者，應准予登記，並自登記之日起，由申請人取得智慧創作專用權", "智慧創作經認定屬於申請人及其他特定原住民族或部落者，自登記之日起，由申請人及其他特定原 住民族或部落共同取得智慧創作專用權", "智慧創作不能認定屬於特定原住民族或部落者，應登記為公共所有，並自登記之日起，由全民取得 智慧創作專用權", "智慧創作專用權人之名稱有變更者，應申請變更登記"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:36:59+00:00", "source_pdf_sha1": "6069e65a1298", "answer_pdf_sha1": "c5158b77d9cd", "source_family": "moex-gov-tw", "moex": {"exam_code": "110150", "c": "401", "s": "0213", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "法學知識與英文(包括中華民國憲法、原住民族行政及法規、英文)", "year": "110", "exam_name": "110年公務人員特種考試外交領事人員及外交行政人員考試、民航人員考試、原住民族考試", "original_question_number": 27, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "一般民政"}'::jsonb, NULL),
  ('aboriginal-e3452428-moex-00388', 'aboriginal-e3452428', 'aboriginal-e3452428-moex-110-6ed013db', 'sub-aboriginal-e3452428-07', NULL, 'single_choice', '依據原住民族工作權保障法處理原住民勞資爭議時，下列敘述何者正確？', '["原住民勞資爭議，應依據勞資爭議處理法規定辦理", "勞資權利事項與調整事項之爭議，勞方當事人有二分之一以上為原住民時，關於調解委員或仲裁委 員有特別規定", "原住民在工作職場發生就業歧視或勞資糾紛，各級主管機關應予以法律諮詢、提供律師及全額訴訟 費之扶助", "直轄市、縣（市）政府依據勞資爭議處理法第30條規定推薦核備之仲裁委員名單中，應至少1人 至3人為具有原住民身分者"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:36:59+00:00", "source_pdf_sha1": "6069e65a1298", "answer_pdf_sha1": "c5158b77d9cd", "source_family": "moex-gov-tw", "moex": {"exam_code": "110150", "c": "401", "s": "0213", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "法學知識與英文(包括中華民國憲法、原住民族行政及法規、英文)", "year": "110", "exam_name": "110年公務人員特種考試外交領事人員及外交行政人員考試、民航人員考試、原住民族考試", "original_question_number": 28, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "一般民政"}'::jsonb, NULL),
  ('aboriginal-e3452428-moex-00389', 'aboriginal-e3452428', 'aboriginal-e3452428-moex-110-6ed013db', 'sub-aboriginal-e3452428-07', NULL, 'single_choice', '關於原住民族實驗教育，下列敘述何者錯誤？', '["教育主管機關為發展原住民族教育，得指定所屬公立高級中等以下學校，或由學校提出申請，辦理 部分班級實驗教育", "國民小學、國民中學辦理原民實驗教育，其課程應依國民小學課程綱要規劃之", "學校辦理原民實驗教育，實驗前徵得學生本人及其法定代理人之同意。但學生已成年者，免經法定 代理人同意", "學校得依經核准之實驗計畫需要，以契約進用教學及工作人員"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:36:59+00:00", "source_pdf_sha1": "6069e65a1298", "answer_pdf_sha1": "c5158b77d9cd", "source_family": "moex-gov-tw", "moex": {"exam_code": "110150", "c": "401", "s": "0213", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "法學知識與英文(包括中華民國憲法、原住民族行政及法規、英文)", "year": "110", "exam_name": "110年公務人員特種考試外交領事人員及外交行政人員考試、民航人員考試、原住民族考試", "original_question_number": 29, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "一般民政"}'::jsonb, NULL),
  ('aboriginal-e3452428-moex-00390', 'aboriginal-e3452428', 'aboriginal-e3452428-moex-110-6ed013db', 'sub-aboriginal-e3452428-07', NULL, 'single_choice', '關於原住民幼兒教保服務，下列敘述何者錯誤？', '["原住民幼兒申請就讀公立幼兒園、非營利幼兒園、社區或部落互助教保服務中心時，有優先權", "部落互助教保服務中心，其招收具原住民身分之幼兒及二親等內任一直系血親具原住民身分之幼 兒，合計應達招收幼兒總人數百分之八十以上", "部落互助教保服務中心，依法有必要且經報直轄市、縣（市）教育及原住民族主管機關會同核准者， 其專任之幼兒園教師、教保員或助理教保員，以經原住民族族語認證且具高級中等學校以上學歷者 替代之", "部落互助教保服務中心專任之幼兒園教師、教保員或助理教保員，得以經原住民族族語認證且具高 級中等學校以上學歷者，全數替代之"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:36:59+00:00", "source_pdf_sha1": "6069e65a1298", "answer_pdf_sha1": "c5158b77d9cd", "source_family": "moex-gov-tw", "moex": {"exam_code": "110150", "c": "401", "s": "0213", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "法學知識與英文(包括中華民國憲法、原住民族行政及法規、英文)", "year": "110", "exam_name": "110年公務人員特種考試外交領事人員及外交行政人員考試、民航人員考試、原住民族考試", "original_question_number": 30, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "一般民政"}'::jsonb, NULL)
